Doc: https://registry.terraform.io/providers/oracle/oci/latest/docs

Múltiplas instâncias:

**count:**
```hcl
resource "oci_core_instance" "web" {
  count          = 3
  display_name   = "web-server-${count.index + 1}"
  # ...
}
```

**for_each (recomendado):**
```hcl
variable "instances" {
  type = map(object({ shape = string; ocpus = number; ad = string }))
}

resource "oci_core_instance" "servers" {
  for_each = var.instances
  display_name = each.key
  shape        = each.value.shape
  shape_config { ocpus = each.value.ocpus }
}
```

**Diferença:** for_each é mais seguro para mudanças (chave nomeada vs índice)

Doc: https://registry.terraform.io/providers/oracle/oci/latest/docs

Boot volume customizado:

```hcl
resource "oci_core_instance" "custom_bv" {
  source_details {
    source_type             = "image"
    source_id               = var.image_ocid
    boot_volume_size_in_gbs = 200
  }
}
```

**Backup policy:**
```hcl
resource "oci_core_volume_backup_policy" "daily" {
  schedules {
    period            = "ONE_DAY"
    retention_seconds = 604800
  }
}

resource "oci_core_boot_volume_backup_policy_assignment" "assign" {
  asset_id  = oci_core_instance.custom_bv.boot_volume_id
  policy_id = oci_core_volume_backup_policy.daily.id
}
```

**VPUs:** 10 (balanced), 20 (high), 30 (highest) [MUTABLE]

Doc: https://registry.terraform.io/providers/oracle/oci/latest/docs

Cluster OKE:

```hcl
resource "oci_containerengine_cluster" "oke" {
  compartment_id     = var.compartment_ocid
  kubernetes_version = "v1.28.2"
  name               = "production-oke"
  vcn_id             = oci_core_vcn.main.id
  endpoint_config {
    is_public_ip_enabled = true
    subnet_id            = oci_core_subnet.k8s_endpoint.id
  }
  options {
    service_lb_subnet_ids = [oci_core_subnet.public.id]
    kubernetes_network_config {
      pods_cidr     = "10.244.0.0/16"
      services_cidr = "10.96.0.0/16"
    }
  }
}

resource "oci_containerengine_node_pool" "nodes" {
  compartment_id     = var.compartment_ocid
  cluster_id         = oci_containerengine_cluster.oke.id
  kubernetes_version = "v1.28.2"
  name               = "general-pool"
  node_shape         = "VM.Standard.E4.Flex"
  node_config_details {
    size = 3
    placement_configs {
      availability_domain = "QnsQ:US-ASHBURN-AD-1"
      subnet_id           = oci_core_subnet.k8s_nodes.id
    }
  }
  node_source_details {
    source_type = "IMAGE"
    image_id    = data.oci_containerengine_node_pool_option.oke.sources[0].image_id
  }
  ssh_public_key = file("~/.ssh/id_rsa.pub")
}
```

Doc: https://registry.terraform.io/providers/oracle/oci/latest/docs

Container Instance (serverless containers):

```hcl
resource "oci_container_instances_container_instance" "app" {
  compartment_id       = var.compartment_ocid
  display_name         = "web-app"
  shape                = "CI.Standard.A1.Flex"
  subnet_id            = oci_core_subnet.private.id
  container_restart_policy = "ALWAYS"
  containers {
    display_name = "web-app"
    image_url    = "iad.ocir.io/my-namespace/my-repo:latest"
    resources {
      memory_in_gbs = 4
      ocpus         = 1
    }
    environment_variables = {
      "APP_ENV" = "production"
    }
  }
}
```

**vs OKE:** Container Instance = single container, simples. OKE = Kubernetes, orquestração

