Para armazenar secrets no OCI Vault e referenciar em instâncias:

1. **Crie o Vault e Key (pré-requisitos)**:
```hcl
resource "oci_kms_vault" "secrets_vault" {
  compartment_id = var.compartment_ocid
  display_name   = "secrets-vault"
  vault_type     = "DEFAULT"
}

resource "oci_kms_key" "encryption_key" {
  compartment_id      = var.compartment_ocid
  display_name        = "secret-encryption-key"
  management_endpoint = oci_kms_vault.secrets_vault.management_endpoint
  key_shape {
    algorithm = "AES"
    length    = 32
  }
}
```

2. **Crie o Secret**:
```hcl
resource "oci_vault_secret" "db_password" {
  compartment_id = var.compartment_ocid
  display_name   = "database-password"
  vault_id       = oci_kms_vault.secrets_vault.id
  key_id         = oci_kms_key.encryption_key.id

  secret_content {
    content_type = "BASE64"
    content      = base64encode("MyS3cur3P@ssw0rd!")
  }
}
```

3. **Referencie o secret em cloud-init**:
```hcl
resource "oci_core_instance" "app_server" {
  compartment_id = var.compartment_ocid
  display_name   = "app-server"
  shape          = "VM.Standard.E4.Flex"
  shape_config {
    ocpus = 2
    memory_in_gbs = 16
  }

  source_details {
    source_type = "image"
    source_id   = var.image_ocid
  }

  metadata = {
    user_data = base64encode(<<-EOF
#!/bin/bash
# O secret é acessado via OCI CLI ou SDK
export DB_PASSWORD_SECRET_ID="${oci_vault_secret.db_password.id}"
oci vault secret get-base64 --secret-id $DB_PASSWORD_SECRET_ID --query \"data.secret-content.content\" --raw-output | base64 -d > /etc/app/db_password
chmod 600 /etc/app/db_password
EOF
  )
  }
}
```

4. **Policies para acesso ao secret**:
```hcl
resource "oci_identity_dynamic_group" "app_dg" {
  compartment_id = var.tenancy_ocid
  name           = "app-server-dg"
  description    = "App servers that need secret access"
  matching_rule  = "ALL {instance.compartment.id = '${var.compartment_ocid}'}"
}

resource "oci_identity_policy" "secret_access_policy" {
  compartment_id = var.compartment_ocid
  name           = "secret-access-policy"
  statements = [
    "Allow dynamic-group ${oci_identity_dynamic_group.app_dg.name} to read secret-family in compartment ${var.compartment_name}",
    "Allow dynamic-group ${oci_identity_dynamic_group.app_dg.name} to use keys in compartment ${var.compartment_name}",
  ]
}
```

5. **Melhor prática**: Nunca hardcode secrets no Terraform. Use variáveis sensíveis:
```hcl
variable "db_password" {
  type      = string
  sensitive = true
}
```

Ref: https://docs.oracle.com/en-us/iaas/Content/KeyManagement/Tasks/managingsecrets.htm

